				_, _ = fmt.Fprintf(opts.Stderr, "[sub-agent] Warning: failed to load memory for %q: %v\n", agentName, memErr)
			}
		} else {
			entries, memErr := memory.LoadEntries(memPath, cfg.Memory.LastN)
			if memErr != nil {
				if opts.Verbose && opts.Stderr != nil {
					_, _ = fmt.Fprintf(opts.Stderr, "[sub-agent] Warning: failed to load memory for %q: %v\n", agentName, memErr)
				}
			} else if entries != "" {
